def int_to_mini_roman(number):
    """
    Given a positive integer, obtain its roman numeral equivalent as a string,
    and return it in lowercase.
    Restrictions: 1 <= num <= 1000

    Examples:
    >>> int_to_mini_roman(19) == 'xix'
    >>> int_to_mini_roman(152) == 'clii'
    >>> int_to_mini_roman(426) == 'cdxxvi'
    """
    if number > 1000 or number < 1:
        return 'error'

    mini_roman = ''

    if number < 4:
        mini_roman = num_to_mini_roman(number)

    elif number < 8:
        mini_roman = num_to_mini_roman(number-5) + num_to_mini_roman(5)

    elif number < 12:
        mini_roman = num_to_mini_roman(number-10) + num_to_mini_roman(10)

    elif number < 16:
        mini_roman = num_to_mini_roman(number-15) + num_to_mini_roman(15)

    elif number < 20:
        mini_roman = num_to_mini_roman(number-20) + num_to_mini_roman(20)

    elif number < 40:
        mini_roman = num_to_mini_roman(number-50) + num_to_mini_roman(50)

    elif number < 80:
        mini_roman = num_to_mini_roman(number-100) + num_to_mini_roman(100)

    elif number < 160:
        mini_roman = num_to_mini_roman(number-150) + num_to_mini_roman(150)

    elif number < 200:
        mini_roman = num_to_mini_roman(number-200) + num_to_mini_roman(200)

    return mini_roman

